// ---------- 绘制按钮 (白圈+红心+金色进度弧) ----------
function drawButton() {
    if (!ctx) return;
    const w = recordCanvas.width, h = recordCanvas.height;
    ctx.clearRect(0, 0, w, h);
    const cx = w/2, cy = h/2;
    const outerR = 30;
    const innerR = 22;

    ctx.beginPath();
    ctx.arc(cx, cy, outerR, 0, Math.PI * 2);
    ctx.strokeStyle = '#ffffff';
    ctx.lineWidth = 3;
    ctx.stroke();

    ctx.beginPath();
    ctx.arc(cx, cy, innerR, 0, Math.PI * 2);
    ctx.fillStyle = '#e34234';
    ctx.fill();

    if (progress > 0 && progress < 1) {
        ctx.beginPath();
        const startAngle = -Math.PI / 2;
        const endAngle = startAngle + (Math.PI * 2 * progress);
        ctx.arc(cx, cy, outerR - 1.5, startAngle, endAngle);
        ctx.strokeStyle = '#ffcc55';
        ctx.lineWidth = 3.5;
        ctx.stroke();
    } else if (progress >= 1) {
        ctx.beginPath();
        ctx.arc(cx, cy, outerR - 1.5, 0, Math.PI * 2);
        ctx.strokeStyle = '#ffcc55';
        ctx.lineWidth = 3.5;
        ctx.stroke();
    }
}

function updateProgressFromAnimTime() {
    if (ringCompleted) return;
    if (currentTime <= REC_START) {
        progress = 0;
    } else if (currentTime >= REC_END) {
        progress = 1;
        ringCompleted = true;
        recordContainer.classList.remove('visible');
        if (anim && !anim.isDestroyed && anim.isPaused && animationStarted) {
            anim.play();
        }
    } else {
        progress = (currentTime - REC_START) / REC_DURATION;
        progress = Math.min(1, Math.max(0, progress));
    }
    drawButton();
}

function setAnimPlay(play) {
    if (!anim || anim.isDestroyed || !animationStarted) return;
    if (play && anim.isPaused) {
        anim.play();
    } else if (!play && !anim.isPaused) {
        anim.pause();
    }
}

function onPointerDown(e) {
    e.preventDefault();
    if (!inRecordZone || ringCompleted) return;
    pressTimer = setTimeout(() => {
        longPressTriggered = true;
        isPressing = true;
        recordTip.classList.add('hide');
        recordCanvas.classList.remove('breathing');
        setAnimPlay(true);
    }, 300);
}

function onPointerUp(e) {
    if (pressTimer) {
        clearTimeout(pressTimer);
        pressTimer = null;
    }
    if (longPressTriggered && isPressing && !ringCompleted) {
        isPressing = false;
        setAnimPlay(false);
        longPressTriggered = false;
    } else {
        longPressTriggered = false;
    }
}

function onPointerCancel(e) {
    if (pressTimer) clearTimeout(pressTimer);
    if (longPressTriggered && isPressing) {
        isPressing = false;
        setAnimPlay(false);
        longPressTriggered = false;
    }
}

// ========== Scene 2 进度条 ==========
function activateScrubber() {
    scrubberActive = true;
    scrubberDragging = false;
    scrubberThumb.classList.remove('dragging');
    scrubberBar.classList.add('visible');
    updateScrubberUI(0);
}

function deactivateScrubber() {
    scrubberActive = false;
    scrubberBar.classList.remove('visible');
}

function updateScrubberUI(pct) {
    const p = Math.round(Math.max(0, Math.min(1, pct)) * 100);
    scrubberFill.style.width = p + '%';
    scrubberThumb.style.left = p + '%';
}

function scrubTo(pct) {
    const clampedPct = Math.max(0, Math.min(1, pct));
    const currentSec = S2_START + clampedPct * S2_DURATION;
    const fr = anim.totalFrames > 0 && animationDuration > 0 ? anim.totalFrames / animationDuration : 30;
    const targetFrame = currentSec * fr;
    anim.goToAndStop(Math.min(targetFrame, anim.totalFrames - 1), true);
    updateScrubberUI(clampedPct);
}

function getScrubberProgress(e) {
    const rect = scrubberTrack.getBoundingClientRect();
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    return (clientX - rect.left) / rect.width;
}

function bindScrubberEvents() {
    scrubberThumb.addEventListener('mousedown', (e) => {
        if (!scrubberActive) return;
        scrubberDragging = true;
        scrubberThumb.classList.add('dragging');
        e.preventDefault();
    });
    document.addEventListener('mousemove', (e) => {
        if (!scrubberDragging) return;
        scrubTo(getScrubberProgress(e));
    });
    document.addEventListener('mouseup', () => {
        scrubberDragging = false;
        scrubberThumb.classList.remove('dragging');
    });

    scrubberThumb.addEventListener('touchstart', (e) => {
        if (!scrubberActive) return;
        scrubberDragging = true;
        scrubberThumb.classList.add('dragging');
        e.preventDefault();
    });
    document.addEventListener('touchmove', (e) => {
        if (!scrubberDragging) return;
        scrubTo(getScrubberProgress(e));
    });
    document.addEventListener('touchend', () => {
        scrubberDragging = false;
        scrubberThumb.classList.remove('dragging');
    });

    // 点击轨道直接跳转
    scrubberTrack.addEventListener('mousedown', (e) => {
        if (!scrubberActive) return;
        if (e.target === scrubberThumb || scrubberThumb.contains(e.target)) return;
        scrubTo(getScrubberProgress(e));
    });
    scrubberTrack.addEventListener('touchstart', (e) => {
        if (!scrubberActive) return;
        if (e.target === scrubberThumb || scrubberThumb.contains(e.target)) return;
        scrubTo(getScrubberProgress(e));
    });
}

function bindRecordEvents() {
    const btn = recordContainer;
    btn.addEventListener('touchstart', onPointerDown, { passive: false });
    btn.addEventListener('touchend', onPointerUp);
    btn.addEventListener('touchcancel', onPointerCancel);
    btn.addEventListener('mousedown', onPointerDown);
    window.addEventListener('mouseup', onPointerUp);
}

// ========== 字幕相关函数 ==========
function typeText(element, fullText, onComplete) {
    if (typeInterval) clearInterval(typeInterval);
    element.innerHTML = '';
    let index = 0;
    const cursorSpan = document.createElement('span');
    cursorSpan.className = 'cursor';
    cursorSpan.innerHTML = '|';
    element.appendChild(cursorSpan);
    typeInterval = setInterval(() => {
        if (index < fullText.length) {
            const char = fullText[index];
            const textNode = document.createTextNode(char);
            element.insertBefore(textNode, cursorSpan);
            index++;
        } else {
            clearInterval(typeInterval);
            typeInterval = null;
            if (cursorSpan.parentNode) cursorSpan.parentNode.removeChild(cursorSpan);
            if (onComplete) onComplete();
        }
    }, TYPE_SPEED_MS);
}

function showSubtitle(act, onHide) {
    if (hideTimeout) clearTimeout(hideTimeout);
    if (typeInterval) clearInterval(typeInterval);
    subtitleTitle.innerText = act.title;
    typeText(subtitleText, act.text, () => {
        hideTimeout = setTimeout(() => {
            subtitleBox.classList.remove('show');
            if (onHide) onHide();
        }, HIDE_DELAY_MS);
    });
    subtitleBox.classList.add('show');
}

function forceHideSubtitle() {
    if (hideTimeout) clearTimeout(hideTimeout);
    if (typeInterval) clearInterval(typeInterval);
    typeInterval = null;
    subtitleBox.classList.remove('show');
    subtitleText.innerHTML = '';
}

// ========== 场景导航：按钮常驻，随时可切 ==========
function updateNavButtons() {
    navPrev.classList.toggle('visible', currentScene > 0);
    navNext.classList.toggle('visible', currentScene < sceneBoundaries.length - 1);
}

function goToScene(idx) {
    if (idx < 0 || idx >= sceneBoundaries.length || !anim || anim.isDestroyed) return;
    if (sceneLock) return;
    sceneLock = true;
    currentScene = idx;
    currentActIndex = -1;
    stallClicked = false;
    fatherClicked = false;
    ringCompleted = false;
    progress = 0;
    isPressing = false;
    longPressTriggered = false;
    animPausedByRecord = false;
    if (pressTimer) { clearTimeout(pressTimer); pressTimer = null; }
    carouselIdx = 0;
    if (carouselSubTimeout) { clearTimeout(carouselSubTimeout); carouselSubTimeout = null; }
    forceHideSubtitle();
    // 切幕时强制隐藏所有交互元素（onEnterFrame 再按当前幕重新显示）
    [clickTree, clickStall, clickFather, clickTree37, clickTree17].forEach(el => {
        if (el) el.classList.remove('visible');
    });
    recordContainer.classList.remove('visible');
    recordTip.classList.remove('hide');
    // 进入 Scene 8 重置交替为 img_0
    if (idx === 7 && imgAltPair) {
        if (imgAltTimer) { clearInterval(imgAltTimer); imgAltTimer = null; }
        imgAltPair.classList.remove('running');
        if (imgAltImgs) { imgAltImgs[0].classList.add('visible'); imgAltImgs[1].classList.remove('visible'); }
    }
    updateNavButtons();
    const targetSec = sceneBoundaries[idx];
    const fr = anim.totalFrames > 0 && animationDuration > 0 ? anim.totalFrames / animationDuration : 30;
    const targetFrame = Math.min(targetSec * fr, anim.totalFrames - 1);

    // Scene 2（idx=1）：暂停在起点，先播字幕，字幕结束后激活进度条
    if (idx === 1) {
        currentActIndex = 1;
        forceHideSubtitle();
        anim.goToAndStop(targetFrame, true);
        animationStarted = true;
        showSubtitle(acts[1], () => {
            activateScrubber();
        });
        return;
    }

    // Scene 3（idx=3,"越来越少"）：3 秒后显示字幕
    if (idx === 3) {
        currentActIndex = 3;
        forceHideSubtitle();
        anim.goToAndPlay(targetFrame, true);
        animationStarted = true;
        if (carouselSubTimeout) clearTimeout(carouselSubTimeout);
        carouselSubTimeout = setTimeout(() => {
            showSubtitle(acts[3]);
        }, 3000);
        return;
    }

    // Scene 5（idx=5,"回来了"）：点击下一幕后才显示字幕
    if (idx === 5) {
        currentActIndex = 5;
        forceHideSubtitle();
        anim.goToAndPlay(targetFrame, true);
        animationStarted = true;
        showSubtitle(acts[5]);
        return;
    }

    // 从 Scene 2 切走时，关闭进度条
    deactivateScrubber();

    // 显式显示对应幕的字幕（避免 checkAct 时序问题导致残留）
    currentActIndex = idx;
    showSubtitle(acts[idx]);

    anim.goToAndPlay(targetFrame, true);
    animationStarted = true;
}

function checkAct(currentSec) {
    if (!anim || anim.isDestroyed) return;
    if (scrubberActive) return;
    let newIndex = -1;
    for (let i = acts.length - 1; i >= 0; i--) {
        if (currentSec >= acts[i].startSec) {
            newIndex = i;
            break;
        }
    }
    if (newIndex !== -1 && newIndex !== currentActIndex && newIndex === currentScene) {
        forceHideSubtitle();
        currentActIndex = newIndex;
        showSubtitle(acts[currentActIndex]);
    }
}

// ========== 帧监听：时间同步 + 场景跟踪（不暂停）+ 录制区间 ==========
function onEnterFrame() {
    if (!anim || anim.isDestroyed || !animationStarted) return;
    if (animationDuration > 0 && anim.totalFrames) {
        currentTime = (anim.currentFrame / anim.totalFrames) * animationDuration;
    } else {
        currentTime = anim.currentFrame / frameRate;
    }

    // 树点击热区显示（Scene 0 内 4.5s 后出现，切到其它幕立即消失）
    if (!scrubberActive && !carouselOverlay.classList.contains('visible') && !carouselOverlayFather.classList.contains('visible')) {
        const inTree = (currentScene === 0 && currentTime >= TREE_SHOW_START);
        clickTree.classList.toggle('visible', inTree);
    }

    // img_37 树点击热区显示（Scene 3，26s起至切幕）
    if (clickTree37 && currentScene === 3) {
        const in37 = (currentTime >= 26);
        clickTree37.classList.toggle('visible', in37);
    } else if (clickTree37) {
        clickTree37.classList.remove('visible');
    }

    // 独立树图层显示（Scene 0，2.28s~3.52s 淡入，切幕消失）
    if (treeContainer && currentScene === 0) {
        const t = currentTime;
        if (t >= TREE_FADE_END) {
            treeContainer.style.opacity = '1';
            treeContainer.classList.add('visible');
        } else if (t >= TREE_FADE_IN) {
            const p = (t - TREE_FADE_IN) / (TREE_FADE_END - TREE_FADE_IN);
            treeContainer.style.opacity = p;
            treeContainer.classList.add('visible');
        } else {
            treeContainer.style.opacity = '0';
            treeContainer.classList.remove('visible');
        }
    } else if (treeContainer) {
        treeContainer.style.opacity = '0';
        treeContainer.classList.remove('visible');
    }

    // 小摊热区显示（15.52s~20.76s，Scene 1~3，scrubbing 或轮播打开时不显示）
    if (!stallClicked && !scrubberActive && !carouselOverlay.classList.contains('visible')) {
        const inStall = (currentScene >= 1 && currentScene <= 3 && currentTime >= STALL_SHOW && currentTime < STALL_HIDE);
        clickStall.classList.toggle('visible', inStall);
    }

    // 父亲热区显示（36.04s 起，保持在当前场景内直到离开第4幕）
    if (!fatherClicked && !scrubberActive && !carouselOverlayFather.classList.contains('visible')) {
        const inFather = (currentTime >= FATHER_SHOW && currentScene === 4);
        clickFather.classList.toggle('visible', inFather);
    }

    // img_17 树点击热区显示（第6幕，50.17s 起；切换下一幕时消失）
    if (clickTree17 && currentScene === 6) {
        const in17 = (currentTime >= 50.17);
        clickTree17.classList.toggle('visible', in17);
    }
    // 切出第6幕：清空粒子 + 隐藏呼吸点
    if (currentScene !== 6) {
        if (particle80Particles.length > 0) {
            particle80Particles.length = 0;
            if (particle80AnimId) { cancelAnimationFrame(particle80AnimId); particle80AnimId = null; }
            if (particle80Ctx) { particle80Ctx.clearRect(0, 0, particle80Canvas.parentElement.clientWidth, particle80Canvas.parentElement.clientHeight); }
        }
        if (clickTree17) { clickTree17.classList.remove('visible'); }
    }
    // img_17 遮挡层同步位置大小
    updateMask17();

    // Scene 8（索引7）交替图片：第66s出现
    if (currentScene === 7 && imgAltPair) {
        const inAlt = (currentTime >= IMGALT_SHOW);
        imgAltPair.classList.toggle('visible', inAlt);
    }
    if (currentScene !== 7 && imgAltPair) {
        if (imgAltTimer) { clearInterval(imgAltTimer); imgAltTimer = null; }
        imgAltPair.classList.remove('visible', 'running');
        if (imgAltImgs) { imgAltImgs[0].classList.add('visible'); imgAltImgs[1].classList.remove('visible'); }
    }

    // 场景边界跟踪（到达边界只暂停，不更新 currentScene，点按钮后由 goToScene 处理跳转）
    const nextIdx = currentScene + 1;
    if (nextIdx < sceneBoundaries.length && currentTime >= sceneBoundaries[nextIdx]) {
        if (anim && !anim.isPaused) {
            anim.pause();
        }
        return;
    }

    // 时间已稳定在当前幕内，解锁导航
    sceneLock = false;

    // 字幕触发
    checkAct(currentTime);

    // 录制区间
    const wasInZone = inRecordZone;
    inRecordZone = (currentTime >= REC_START && currentTime < REC_END && !ringCompleted);

    if (inRecordZone && !wasInZone) {
        if (!ringCompleted) {
            setAnimPlay(false);
            animPausedByRecord = true;
            recordContainer.classList.add('visible');
            recordTip.classList.remove('hide');
            recordCanvas.classList.add('breathing');
            updateProgressFromAnimTime();
        }
    } else if (!inRecordZone && wasInZone) {
        recordContainer.classList.remove('visible');
        if (!ringCompleted && currentTime >= REC_END) {
            ringCompleted = true;
            progress = 1;
            drawButton();
        }
        if (animPausedByRecord && !ringCompleted) {
            setAnimPlay(true);
            animPausedByRecord = false;
        }
    }

    if (inRecordZone && !ringCompleted) {
        updateProgressFromAnimTime();
    }

}

// ========== 初始化动画 ==========
function initAnimation() {
    if (anim) {
        anim.destroy();
        anim = null;
    }
    currentActIndex = -1;
    currentScene = 0;
    animationStarted = false;
    stallClicked = false;
    fatherClicked = false;
    inRecordZone = false;
    ringCompleted = false;
    progress = 0;
    longPressTriggered = false;
    isPressing = false;
    animPausedByRecord = false;
    if (pressTimer) clearTimeout(pressTimer);
    forceHideSubtitle();
    recordContainer.classList.remove('visible');
    recordTip.classList.remove('hide');
    recordCanvas.classList.add('breathing');
    drawButton();

    loadingDiv.style.display = 'flex';
    loadingDiv.classList.remove('hide');
    errorPanel.classList.remove('show');

    // 使用内嵌数据，无需 fetch
    try {
        const animData = EMBEDDED_ANIM_DATA;

        // img_28（女孩）延迟 0.5 秒出现（opacity 关键帧整体 +15 帧）
        const girlLayer = animData.layers.find(l => l.refId === 'image_28');
        if (girlLayer && girlLayer.ks && girlLayer.ks.o && Array.isArray(girlLayer.ks.o.k)) {
            girlLayer.ks.o.k.forEach(kf => { kf.t += 15; });
        }

        // img_2 位置改为 [300, 460]
        const img2Layer = animData.layers.find(l => l.refId === 'image_2');
        if (img2Layer?.ks?.p && Array.isArray(img2Layer.ks.p.k)) {
            img2Layer.ks.p.k[0] = 320;
            img2Layer.ks.p.k[1] = 460;
        }

        const durationFrames = animData.op - animData.ip;
            frameRate = animData.fr || 30;
            animationDuration = durationFrames / frameRate;

            anim = lottie.loadAnimation({
                container: document.getElementById('lottie-container'),
                renderer: 'svg',
                loop: false,
                autoplay: false,
                animationData: animData,
                rendererSettings: {
                    preserveAspectRatio: 'xMinYMin meet',
                    clearCanvas: true
                }
            });

            anim.addEventListener('DOMLoaded', () => {
                // 抓取 Lottie 中两个"树"图层的 DOM 元素，后续用独立树替代
                lottieTreeLayers = Array.from(document.querySelectorAll('#lottie-container [data-nm="树"]'));
                lottieTreeLayers.forEach(el => el.style.display = 'none');

                // 点击加载页后开始播放
                loadingDiv.style.cursor = 'pointer';
                loadingDiv.addEventListener('click', function startPlay() {
                    loadingDiv.removeEventListener('click', startPlay);
                    loadingDiv.classList.add('hide');
                    setTimeout(() => {
                        loadingDiv.style.display = 'none';
                        anim.play();
                        animationStarted = true;
                        updateNavButtons();
                        anim.addEventListener('enterFrame', onEnterFrame);
                        anim.addEventListener('complete', () => {
                            animationStarted = false;
                            currentScene = sceneBoundaries.length - 1;
                            recordContainer.classList.remove('visible');
                            updateNavButtons();
                        });
                    }, 600);
                }, { once: true });
            });

            anim.addEventListener('error', (err) => {
                console.error(err);
                if (!animationStarted) showError('动画渲染失败');
            });
    } catch(err) {
        console.error(err);
        showError('资源加载失败，请检查 JSON 数据');
    }
}

function showError(msg) {
    loadingDiv.classList.add('hide');
    setTimeout(() => loadingDiv.style.display = 'none', 300);
    const errDiv = errorPanel.querySelector('div:first-child');
    if (errDiv) errDiv.innerText = msg;
    errorPanel.classList.add('show');
}

// ========== 容器等比缩放 ==========
function fitContainer() {
    const el = document.getElementById('lottie-container');
    const tree = document.getElementById('tree-container');
    const ct = document.getElementById('clickTree');
    const vw = window.innerWidth;
    const vh = window.innerHeight;
    const scale = Math.min(vw / 375, vh / 667);
    el.style.transform = `translate(-50%, -50%) scale(${scale})`;
    if (tree) tree.style.transform = `translate(-50%, -50%) scale(${scale})`;

    // Lottie 容器在视口中的左上角偏移
    const offsetX = (vw - 375 * scale) / 2;
    const offsetY = (vh - 667 * scale) / 2;
    const hs = 60; // 热点半宽 (120/2)

    if (ct) {
        ct.style.left = (offsetX + TREE_HOTSPOT.x * scale - hs) + 'px';
        ct.style.top  = (offsetY + TREE_HOTSPOT.y * scale - hs) + 'px';
    }
    if (clickTree37) {
        clickTree37.style.left = (offsetX + TREE37_HOTSPOT.x * scale - hs) + 'px';
        clickTree37.style.top  = (offsetY + TREE37_HOTSPOT.y * scale - hs) + 'px';
    }
    if (clickTree17) {
        const hs17 = 100; // 热点半宽 (200/2)
        clickTree17.style.left = (offsetX + TREE17_HOTSPOT.x * scale - hs17) + 'px';
        clickTree17.style.top  = (offsetY + TREE17_HOTSPOT.y * scale - hs17) + 'px';
    }
    // Scene 8 交替图片：跟随 Lottie 缩放定位
    if (imgAltPair) {
        imgAltPair.style.left = (offsetX + (-120) * scale) + 'px';
        imgAltPair.style.top  = (offsetY + 166.75 * scale) + 'px';
        imgAltPair.style.width = (375 * scale) + 'px';
    }
    // img_17 遮挡层同步（resize 时也更新）
    updateMask17();
}
fitContainer();
window.addEventListener('resize', fitContainer);

// ========== 事件绑定 ==========
retryBtn.addEventListener('click', () => {
    initAnimation();
});

navPrev.addEventListener('click', (e) => {
    e.stopPropagation();
    if (currentScene > 0) goToScene(currentScene - 1);
});
navNext.addEventListener('click', (e) => {
    e.stopPropagation();
    if (currentScene < sceneBoundaries.length - 1) goToScene(currentScene + 1);
});

// ========== img_17 树点击 → 8.0 粒子动画（Canvas）==========
// 预加载 8.0.png
(function preloadParticle80() {
    const img = new Image();
    img.onload = () => { particle80Image = img; };
    img.src = 'images/8.0.png';
})();

// 重置 Canvas 尺寸（适配 DPR）
function resizeParticle80Canvas() {
    if (!particle80Canvas) return;
    const dpr = window.devicePixelRatio || 1;
    // Canvas 在 lottie-container 内，375×667 坐标空间（容器 transform 自动缩放）
    particle80Canvas.width = 375 * dpr;
    particle80Canvas.height = 667 * dpr;
    particle80Canvas.style.width = '375px';
    particle80Canvas.style.height = '667px';
    particle80Ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
}


// ========== img_17 遮挡层（与 Lottie "树"图层同步位置大小）==========
// Lottie: fr=25, 锚点=[1024,1024], 图片 2048×2048
// 位置关键帧: t=1263(50.52s)→[33.825,133], t=1520(60.8s)→[33.825,133], t=1533(61.32s)→[160.05,139]
// 缩放关键帧: t=1263→[51.5,51.5]%, t=1520→[51.5,51.5]%, t=1533→[40,40]%
const IMG17_FR = 25;
const IMG17_ANCHOR = 1024; // 锚点 x,y
const IMG17_W = 2048;
const IMG17_H = 2048;

function lerp(a, b, t) { return a + (b - a) * t; }

function getImg17Transform(currentTime) {
    const frame = currentTime * IMG17_FR;
    let px, py, sx;
    if (frame <= 1263) { px = 33.825; py = 133; sx = 51.5; }
    else if (frame <= 1520) { px = 33.825; py = 133; sx = 51.5; }
    else if (frame <= 1533) {
        const t = (frame - 1520) / 13;
        px = lerp(33.825, 160.05, t);
        py = lerp(133, 139, t);
        sx = lerp(51.5, 40, t);
    } else { px = 160.05; py = 139; sx = 40; }
    return { px, py, sx };
}

function updateMask17() {
    if (!mask17) return;
    if (currentScene !== 6) { mask17.style.display = 'none'; return; }
    const { px, py, sx } = getImg17Transform(currentTime);
    // mask17 已移入 lottie-container，坐标相对于容器 375 空间（transform 自动缩放）
    mask17.style.display = 'block';
    mask17.style.left = (px - IMG17_ANCHOR * sx / 100) + 'px';
    mask17.style.top  = (py - IMG17_ANCHOR * sx / 100) + 'px';
    mask17.style.width = (IMG17_W * sx / 100) + 'px';
    mask17.style.height = (IMG17_H * sx / 100) + 'px';
}

// 生成一个 8.0 粒子（从喷发原点出发，匀速下落，每个粒子固定随机大小）
// 呼吸点坐标改 TREE17_HOTSPOT，粒子喷发原点改 PARTICLE80_ORIGIN
function createParticle80(cx, cy) {
    const size = 30 + Math.random() * 50;       // 每个粒子固定随机大小（有的大的有的小）
    return {
        x: cx + (Math.random() - 0.5) * 80,    // 水平分散（±40px）
        y: cy,
        size: size,
        vx: (Math.random() - 0.5) * 1.5,        // 水平飘散
        vy: 0.4 + Math.random() * 1.0,           // 慢速下落
        rotation: Math.random() * Math.PI * 2,
        rotSpeed: (Math.random() - 0.5) * 0.03,
        opacity: 0.8 + Math.random() * 0.2,
    };
}

// 8.0 粒子动画循环（匀速下落，每个粒子固定随机大小）
function animateParticles80() {
    if (!particle80Ctx || (particle80Particles.length === 0)) {
        particle80AnimId = null;
        return;
    }
    const w = particle80Canvas.parentElement.clientWidth;
    const h = particle80Canvas.parentElement.clientHeight;
    particle80Ctx.clearRect(0, 0, w, h);

    // 先画粒子（在底层）
    for (let i = particle80Particles.length - 1; i >= 0; i--) {
        const p = particle80Particles[i];

        // 匀速下落 + 轻微水平飘动
        p.x += p.vx;
        p.y += p.vy;

        p.rotation += p.rotSpeed;
        p.opacity -= 0.00006;                    // 更慢速淡出

        if (p.y > h + 500 || p.opacity <= 0) {
            particle80Particles.splice(i, 1);
            continue;
        }

        particle80Ctx.save();
        particle80Ctx.globalAlpha = Math.max(0, p.opacity);
        particle80Ctx.translate(p.x, p.y);
        particle80Ctx.rotate(p.rotation);
        particle80Ctx.drawImage(particle80Image, -p.size / 2, -p.size / 2, p.size, p.size);
        particle80Ctx.restore();
    }

    if (particle80Particles.length > 0) {
        particle80AnimId = requestAnimationFrame(animateParticles80);
    } else {
        particle80AnimId = null;
    }
}

// 点击触发粒子爆发（从 PARTICLE80_ORIGIN 出发，独立于呼吸点）
function burstParticles80() {
    if (!particle80Image) return;
    resizeParticle80Canvas();
    // Canvas 在 lottie-container 内，直接使用 375 坐标空间
    const cx = PARTICLE80_ORIGIN.x;
    const cy = PARTICLE80_ORIGIN.y;
    // 生成 50 个粒子
    for (let i = 0; i < 50; i++) {
        particle80Particles.push(createParticle80(cx, cy));
    }
    if (!particle80AnimId) animateParticles80();
}

if (clickTree17) {
    clickTree17.addEventListener('click', () => {
        burstParticles80();                         // 点击出花瓣，呼吸点不消失
    });
    clickTree17.addEventListener('touchstart', (e) => {
        e.preventDefault();
        clickTree17.click();
    });
}

