// ========== 树点击 → 落叶粒子（8.6.png，第1幕）==========
// 预加载落叶图片
(function preloadLeaf() {
    const img = new Image();
    img.onload = () => { leafImage = img; };
    img.src = 'images/8.6.png';
})();

// 重新设置 Canvas 尺寸（适配移动端 DPR）
function resizeLeafCanvas() {
    const rect = leafCanvas.parentElement.getBoundingClientRect();
    const dpr = window.devicePixelRatio || 1;
    leafCanvas.width = rect.width * dpr;
    leafCanvas.height = rect.height * dpr;
    leafCanvas.style.width = rect.width + 'px';
    leafCanvas.style.height = rect.height + 'px';
    leafCtx.setTransform(dpr, 0, 0, dpr, 0, 0);
}

// 生成一片落叶（与落花效果一致：简单匀速飘落）
function createLeaf() {
    const w = leafCanvas.parentElement.clientWidth;
    const h = leafCanvas.parentElement.clientHeight;
    const x = w * (0.08 + Math.random() * 0.12);
    const y = h * (0.08 + Math.random() * 0.08);
    const size = 14 + Math.random() * 26;
    return {
        x, y, size,
        vx: (Math.random() - 0.5) * 1.5,           // 水平飘散（与落花一致）
        vy: 0.4 + Math.random() * 1.0,             // 慢速下落（与落花一致）
        rotation: Math.random() * Math.PI * 2,
        rotSpeed: (Math.random() - 0.5) * 0.03,
        opacity: 0.8 + Math.random() * 0.2,
    };
}

// 落叶动画循环（与落花效果一致：匀速飘落 + 轻微旋转）
function animateLeaves() {
    if (!leavesActive && leafParticles.length === 0) { leafAnimId = null; return; }
    const w = leafCanvas.parentElement.clientWidth;
    const h = leafCanvas.parentElement.clientHeight;
    leafCtx.clearRect(0, 0, w, h);

    for (let i = leafParticles.length - 1; i >= 0; i--) {
        const p = leafParticles[i];

        // 匀速下落 + 水平飘散（与落花一致）
        p.x += p.vx;
        p.y += p.vy;
        p.rotation += p.rotSpeed;
        p.opacity -= 0.00006;                      // 与落花一致的淡出速度

        if (p.y > h + 60 || p.opacity <= 0) {
            leafParticles.splice(i, 1);
            continue;
        }

        leafCtx.save();
        leafCtx.globalAlpha = Math.max(0, p.opacity);
        leafCtx.translate(p.x, p.y);
        leafCtx.rotate(p.rotation);
        leafCtx.drawImage(leafImage, -p.size / 2, -p.size / 2, p.size, p.size);
        leafCtx.restore();
    }

    // 持续生成新叶子（粒子上限 120）
    if (leavesActive && leafParticles.length < 120 && Math.random() < 0.88) {
        leafParticles.push(createLeaf());
    }

    if (leafParticles.length > 0 || leavesActive) {
        leafAnimId = requestAnimationFrame(animateLeaves);
    } else {
        leafAnimId = null;
    }
}

// 开始落叶（重复点击累加粒子，不清空已有叶子）
function startLeaves() {
    resizeLeafCanvas();
    // 每次点击追加 35 片，上限 150
    const startLen = leafParticles.length;
    const target = Math.min(startLen + 35, 150);
    for (let i = startLen; i < target; i++) {
        leafParticles.push(createLeaf());
    }
    leavesActive = true;
    // 每次点击刷新 5 秒生成窗口
    clearTimeout(startLeaves._stopTimer);
    startLeaves._stopTimer = setTimeout(() => {
        leavesActive = false;
    }, 5000);
    if (!leafAnimId) animateLeaves();
}

// 树点击事件
clickTree.addEventListener('click', () => {
    if (!leafImage) return;
    startLeaves();
});
clickTree.addEventListener('touchstart', (e) => {
    e.preventDefault();
    clickTree.click();
});

// img_37 树点击事件：播放 22s~27s
clickTree37.addEventListener('click', () => {
    if (!anim) return;
    const targetFrame = 22 * frameRate;
    const endFrame = 27 * frameRate;
    if (tree37FrameHandler) anim.removeEventListener('enterFrame', tree37FrameHandler);
    anim.goToAndPlay(targetFrame, true);
    tree37FrameHandler = () => {
        if (anim.currentFrame >= endFrame) {
            anim.pause();
            anim.removeEventListener('enterFrame', tree37FrameHandler);
            tree37FrameHandler = null;
        }
    };
    anim.addEventListener('enterFrame', tree37FrameHandler);
});
clickTree37.addEventListener('touchstart', (e) => {
    e.preventDefault();
    clickTree37.click();
});

let carouselSubTimeout = null;

function openCarousel() {
    carouselIdx = 0;
    updateCarousel();
    carouselOverlay.classList.add('visible');
    renderDots();
    // 先隐藏当前字幕，1 秒后再显示"越来越少"
    forceHideSubtitle();
    carouselSubTimeout = setTimeout(() => {
        showSubtitle(acts[3]);
    }, 3000);
}

function closeCarousel() {
    carouselOverlay.classList.remove('visible');
    stallClicked = false;
    carouselIdx = 0;
    if (carouselSubTimeout) { clearTimeout(carouselSubTimeout); carouselSubTimeout = null; }
    forceHideSubtitle();
    if (anim && anim.isPaused) anim.play();
}

function goCarousel(idx) {
    carouselIdx = Math.max(0, Math.min(CAROUSEL_COUNT - 1, idx));
    updateCarousel();
    renderDots();
}

function updateCarousel() {
    carouselTrack.style.transform = `translateX(-${carouselIdx * 100}%)`;
}

function renderDots() {
    carouselDots.innerHTML = '';
    for (let i = 0; i < CAROUSEL_COUNT; i++) {
        const dot = document.createElement('div');
        dot.className = 'carousel-dot' + (i === carouselIdx ? ' active' : '');
        dot.addEventListener('click', () => goCarousel(i));
        carouselDots.appendChild(dot);
    }
}

document.getElementById('carouselClose').addEventListener('click', closeCarousel);
document.getElementById('carouselPrev').addEventListener('click', () => goCarousel(carouselIdx - 1));
document.getElementById('carouselNext').addEventListener('click', () => goCarousel(carouselIdx + 1));

// ========== 父亲轮播函数 ==========
function updateCarouselFather() {
    carouselTrackFather.style.transform = `translateX(-${carouselIdxFather * 100}%)`;
}

function renderDotsFather() {
    carouselDotsFather.innerHTML = '';
    for (let i = 0; i < CAROUSEL_FATHER_COUNT; i++) {
        const dot = document.createElement('div');
        dot.className = 'carousel-dot' + (i === carouselIdxFather ? ' active' : '');
        dot.addEventListener('click', () => goCarouselFather(i));
        carouselDotsFather.appendChild(dot);
    }
}

function openCarouselFather() {
    carouselIdxFather = 0;
    updateCarouselFather();
    carouselOverlayFather.classList.add('visible');
    renderDotsFather();
    forceHideSubtitle();
}

function closeCarouselFather() {
    carouselOverlayFather.classList.remove('visible');
    fatherClicked = false;
    carouselIdxFather = 0;
    forceHideSubtitle();
    if (anim && anim.isPaused) anim.play();
}

function goCarouselFather(idx) {
    carouselIdxFather = Math.max(0, Math.min(CAROUSEL_FATHER_COUNT - 1, idx));
    updateCarouselFather();
    renderDotsFather();
}

document.getElementById('carouselCloseFather').addEventListener('click', closeCarouselFather);
document.getElementById('carouselPrevFather').addEventListener('click', () => goCarouselFather(carouselIdxFather - 1));
document.getElementById('carouselNextFather').addEventListener('click', () => goCarouselFather(carouselIdxFather + 1));

// 触摸滑动
let touchStartX = 0;
carouselTrack.addEventListener('touchstart', (e) => {
    touchStartX = e.touches[0].clientX;
}, { passive: true });
carouselTrack.addEventListener('touchend', (e) => {
    const dx = e.changedTouches[0].clientX - touchStartX;
    if (Math.abs(dx) > 40) {
        goCarousel(carouselIdx + (dx < 0 ? 1 : -1));
    }
});

// 父亲轮播触摸滑动
let touchStartXFather = 0;
carouselTrackFather.addEventListener('touchstart', (e) => {
    touchStartXFather = e.touches[0].clientX;
}, { passive: true });
carouselTrackFather.addEventListener('touchend', (e) => {
    const dx = e.changedTouches[0].clientX - touchStartXFather;
    if (Math.abs(dx) > 40) {
        goCarouselFather(carouselIdxFather + (dx < 0 ? 1 : -1));
    }
});

